23	#include "mupdf/fitz.h"
24	#include "mupdf/pdf.h"
25	
26	#include <string.h>
27	
28	#define PDF_MAX_NAME_LENGTH 4095
29	
30	#define IS_NUMBER \
31		'+':case'-':case'.':case'0':case'1':case'2':case'3':\
32		case'4':case'5':case'6':case'7':case'8':case'9'
33	#define IS_WHITE \
34		'\x00':case'\x09':case'\x0a':case'\x0c':case'\x0d':case'\x20'
35	#define IS_HEX \
36		'0':case'1':case'2':case'3':case'4':case'5':case'6':\
37		case'7':case'8':case'9':case'A':case'B':case'C':\
38		case'D':case'E':case'F':case'a':case'b':case'c':\
39		case'd':case'e':case'f'
40	#define IS_DELIM \
41		'(':case')':case'<':case'>':case'[':case']':case'{':\
42		case'}':case'/':case'%'
43	
44	#define RANGE_0_9 \
45		'0':case'1':case'2':case'3':case'4':case'5':\
46		case'6':case'7':case'8':case'9'
47	#define RANGE_a_f \
48		'a':case'b':case'c':case'd':case'e':case'f'
49	#define RANGE_A_F \
50		'A':case'B':case'C':case'D':case'E':case'F'
51	#define RANGE_0_7 \
52		'0':case'1':case'2':case'3':case'4':case'5':case'6':case'7'
53	
54	/* #define DUMP_LEXER_STREAM */
55	#ifdef DUMP_LEXER_STREAM
56	static inline int lex_byte(fz_context *ctx, fz_stream *stm)
57	{
58		int c = fz_read_byte(ctx, stm);
59	
60		if (c == EOF)
61			fz_write_printf(ctx, fz_stdout(ctx), "<EOF>");
62		else if (c >= 32 && c < 128)
63			fz_write_printf(ctx, fz_stdout(ctx), "%c", c);
64		else
65			fz_write_printf(ctx, fz_stdout(ctx), "<%02x>", c);
66		return c;
67	}
68	#else
69	#define lex_byte(C,S) fz_read_byte(C,S)
70	#endif
71	
72	static inline int iswhite(int ch)
73	{
74		return
75			ch == '\000' ||
76			ch == '\011' ||
77			ch == '\012' ||
78			ch == '\014' ||
79			ch == '\015' ||
80			ch == '\040';
81	}
82	
83	static inline int fz_isprint(int ch)
84	{
85		return ch >= ' ' && ch <= '~';
86	}
87	
88	static inline int unhex(int ch)
89	{
90		if (ch >= '0' && ch <= '9') return ch - '0';
91		if (ch >= 'A' && ch <= 'F') return ch - 'A' + 0xA;
92		if (ch >= 'a' && ch <= 'f') return ch - 'a' + 0xA;
93		return 0;
94	}
95	
96	static void
97	lex_white(fz_context *ctx, fz_stream *f)
98	{
99		int c;
100		do {
101			c = lex_byte(ctx, f);
102		} while ((c <= 32) && (iswhite(c)));
103		if (c != EOF)
104			fz_unread_byte(ctx, f);
105	}
106	
107	static void
108	lex_comment(fz_context *ctx, fz_stream *f)
109	{
110		int c;
111		do {
112			c = lex_byte(ctx, f);
113		} while ((c != '\012') && (c != '\015') && (c != EOF));
114	}
115	
116	/* Fast(ish) but inaccurate strtof, with Adobe overflow handling. */
117	static float acrobat_compatible_atof(char *s)
118	{
119		int neg = 0;
120		unsigned int i = 0;
121	
122		while (*s == '-')
123		{
124			neg = 1;
125			++s;
126		}
127		while (*s == '+')
128		{
129			++s;
130		}
131	
132		while (*s >= '0' && *s <= '9')
133		{
134			/* We deliberately ignore overflow here.
135			 * Tests show that Acrobat handles * overflows in exactly the same way we do:
136			 * 123450000000000000000678 is read as 678.
137			 */
138			i = i * 10 + (*s - '0');
139			++s;
140		}
141	
142		if (*s == '.')
143		{
144			float v = i;
145			float n = 0;
146			float d = 1;
147			++s;
148			while (*s >= '0' && *s <= '9')
149			{
150				n = 10 * n + (*s - '0');
151				d = 10 * d;
152				++s;
153			}
154			v += n / d;
155			return neg ? -v : v;
156		}
157		else
158		{
159			return neg ? -i : i;
160		}
161	}
162	
163	/* Fast but inaccurate atoi. */
164	static int64_t fast_atoi(char *s)
165	{
166		int neg = 0;
167		uint64_t i = 0;
168	
169		while (*s == '-')
170		{
171			neg = 1;
172			++s;
173		}
174		while (*s == '+')
175		{
176			++s;
177		}
178	
179		while (*s >= '0' && *s <= '9')
180		{
181			/* We deliberately ignore overflow here. */
182			i = i * 10 + (*s - '0');
183			++s;
184		}
185	
186		return neg ? -i : i;
187	}
188	
189	static int
190	lex_number(fz_context *ctx, fz_stream *f, pdf_lexbuf *buf, int c)
191	{
192		char *s = buf->scratch;
193		char *e = buf->scratch + buf->size - 1; /* leave space for zero terminator */
194		char *isreal = (c == '.' ? s : NULL);
195		int neg = (c == '-');
196		int isbad = 0;
197	
198		*s++ = c;
199	
200		c = lex_byte(ctx, f);
201	
202		/* skip extra '-' signs at start of number */
203		if (neg)
204		{
205			while (c == '-')
206				c = lex_byte(ctx, f);
207		}
208	
209		while (s < e)
210		{
211			switch (c)
212			{
213			case IS_WHITE:
214			case IS_DELIM:
215				fz_unread_byte(ctx, f);
216				goto end;
217			case EOF:
218				goto end;
219			case '.':
220				if (isreal)
221					isbad = 1;
222				isreal = s;
223				*s++ = c;
224				break;
225			case '-':
226				/* Bug 703248: Some PDFs (particularly those
227				 * generated by google docs) apparently have
228				 * numbers like 0.000000000000-5684342 in them.
229				 * We'll stop our interpretation at the -, but
230				 * keep reading to skip over the trailing
231				 * digits so they aren't parsed later. */
232				*s++ = '\0';
233				break;
234			case RANGE_0_9:
235				*s++ = c;
236				break;
237			default:
238				isbad = 1;
239				*s++ = c;
240				break;
241			}
242			c = lex_byte(ctx, f);
243		}
244	
245	end:
246		*s = '\0';
247		if (isbad)
248			return PDF_TOK_KEYWORD;
249		if (isreal)
250		{
251			/* We'd like to use the fastest possible atof
252			 * routine, but we'd rather match acrobats
253			 * handling of broken numbers. As such, we
254			 * spot common broken cases and call an
255			 * acrobat compatible routine where required. */
256			if (neg > 1 || isreal - buf->scratch >= 10)
257				buf->f = acrobat_compatible_atof(buf->scratch);
258			else
259				buf->f = fz_atof(buf->scratch);
260			return PDF_TOK_REAL;
261		}
262		else
263		{
264			buf->i = fast_atoi(buf->scratch);
265			return PDF_TOK_INT;
266		}
267	}
268	
269	static void
270	lex_name(fz_context *ctx, fz_stream *f, pdf_lexbuf *lb)
271	{
272		char *s = lb->scratch;
273		char *e = s + fz_minz(PDF_MAX_NAME_LENGTH, lb->size);
274		int c;
275	
276		while (1)
277		{
278			if (s == e)
279			{
280				if (e - lb->scratch < PDF_MAX_NAME_LENGTH)
281				{
282					s += pdf_lexbuf_grow(ctx, lb);
283					e = lb->scratch + fz_minz(PDF_MAX_NAME_LENGTH, lb->size);
284				}
285				else
286				{
287					/* truncate names that are too long */
288					fz_warn(ctx, "name is too long");
289					*s = 0;
290					lb->len = s - lb->scratch;
291					s = NULL;
292				}
293			}
294			c = lex_byte(ctx, f);
295			switch (c)
296			{
297			case IS_WHITE:
298			case IS_DELIM:
299				fz_unread_byte(ctx, f);
300				goto end;
301			case EOF:
302				goto end;
303			case '#':
304			{
305				int hex[2];
306				int i;
307				for (i = 0; i < 2; i++)
308				{
309					c = fz_peek_byte(ctx, f);
310					switch (c)
311					{
312					case RANGE_0_9:
313						if (i == 1 && c == '0' && hex[0] == 0)
314							goto illegal;
315						hex[i] = lex_byte(ctx, f) - '0';
316						break;
317					case RANGE_a_f:
318						hex[i] = lex_byte(ctx, f) - 'a' + 10;
319						break;
320					case RANGE_A_F:
321						hex[i] = lex_byte(ctx, f) - 'A' + 10;
322						break;
323					default:
324						goto illegal;
325					case EOF:
326						goto illegal_eof;
327					}
328				}
329				if (s) *s++ = (hex[0] << 4) + hex[1];
330				break;
331	illegal:
332				if (i == 1)
333					fz_unread_byte(ctx, f);
334	illegal_eof:
335				if (s) *s++ = '#';
336				continue;
337			}
338			default:
339				if (s) *s++ = c;
340				break;
341			}
342		}
343	end:
344		if (s)
345		{
346			*s = '\0';
347			lb->len = s - lb->scratch;
348		}
349	}
350	
351	static int
352	lex_string(fz_context *ctx, fz_stream *f, pdf_lexbuf *lb)
353	{
354		char *s = lb->scratch;
355		char *e = s + lb->size;
356		int bal = 1;
357		int oct;
358		int c;
359	
360		while (1)
361		{
362			if (s == e)
363			{
364				s += pdf_lexbuf_grow(ctx, lb);
365				e = lb->scratch + lb->size;
366			}
367			c = lex_byte(ctx, f);
368			switch (c)
369			{
370			case EOF:
371				return PDF_TOK_ERROR;
372			case '(':
373				bal++;
374				*s++ = c;
375				break;
376			case ')':
377				bal --;
378				if (bal == 0)
379					goto end;
380				*s++ = c;
381				break;
382			case '\\':
383				c = lex_byte(ctx, f);
384				switch (c)
385				{
386				case EOF:
387					return PDF_TOK_ERROR;
388				case 'n':
389					*s++ = '\n';
390					break;
391				case 'r':
392					*s++ = '\r';
393					break;
394				case 't':
395					*s++ = '\t';
396					break;
397				case 'b':
398					*s++ = '\b';
399					break;
400				case 'f':
401					*s++ = '\f';
402					break;
403				case '(':
404					*s++ = '(';
405					break;
406				case ')':
407					*s++ = ')';
408					break;
409				case '\\':
410					*s++ = '\\';
411					break;
412				case RANGE_0_7:
413					oct = c - '0';
414					c = lex_byte(ctx, f);
415					if (c >= '0' && c <= '7')
416					{
417						oct = oct * 8 + (c - '0');
418						c = lex_byte(ctx, f);
419						if (c >= '0' && c <= '7')
420							oct = oct * 8 + (c - '0');
421						else if (c != EOF)
422							fz_unread_byte(ctx, f);
423					}
424					else if (c != EOF)
425						fz_unread_byte(ctx, f);
426					*s++ = oct;
427					break;
428				case '\n':
429					break;
430				case '\r':
431					c = lex_byte(ctx, f);
432					if ((c != '\n') && (c != EOF))
433						fz_unread_byte(ctx, f);
434					break;
435				default:
436					*s++ = c;
437				}
438				break;
439			/* Bug 708256: PDF 32000-1 says that any occurence of \n, \r, or \r\n in a
440			 * (unless escaped with a '\') should be interpreted as a single 0x0a byte. */
441			case '\n':
442				*s++ = 0x0a;
443				break;
444			case '\r':
445				*s++ = 0x0a;
446				c = lex_byte(ctx, f);
447				if ((c != '\n') && (c != EOF))
448					fz_unread_byte(ctx, f);
449				break;
450			default:
451				*s++ = c;
452				break;
453			}
454		}
455	end:
456		lb->len = s - lb->scratch;
457		return PDF_TOK_STRING;
458	}
459	
460	static int
461	lex_hex_string(fz_context *ctx, fz_stream *f, pdf_lexbuf *lb)
462	{
463		char *s = lb->scratch;
464		char *e = s + lb->size;
465		int a = 0, x = 0;
466		int c;
467	
468		while (1)
469		{
470			if (s == e)
471			{
472				s += pdf_lexbuf_grow(ctx, lb);
473				e = lb->scratch + lb->size;
474			}
475			c = lex_byte(ctx, f);
476			switch (c)
477			{
478			case IS_WHITE:
479				break;
480			default:
481				fz_warn(ctx, "invalid character in hex string");
482				/* fall through */
483			case IS_HEX:
484				if (x)
485				{
486					*s++ = a * 16 + unhex(c);
487					x = !x;
488				}
489				else
490				{
491					a = unhex(c);
492					x = !x;
493				}
494				break;
495			case '>':
496				if (x)
497				{
498					*s++ = a * 16; /* pad truncated string with '0' */
499				}
500				goto end;
501			case EOF:
502				return PDF_TOK_ERROR;
503			}
504		}
505	end:
506		lb->len = s - lb->scratch;
507		return PDF_TOK_STRING;
508	}
509	
510	static pdf_token
511	pdf_token_from_keyword(char *key)
512	{
513		switch (*key)
514		{
515		case 'R':
516			if (!strcmp(key, "R")) return PDF_TOK_R;
517			break;
518		case 't':
519			if (!strcmp(key, "true")) return PDF_TOK_TRUE;
520			if (!strcmp(key, "trailer")) return PDF_TOK_TRAILER;
521			break;
522		case 'f':
523			if (!strcmp(key, "false")) return PDF_TOK_FALSE;
524			break;
525		case 'n':
526			if (!strcmp(key, "null")) return PDF_TOK_NULL;
527			if (!strcmp(key, "newobj")) return PDF_TOK_NEWOBJ;
528			break;
529		case 'o':
530			if (!strcmp(key, "obj")) return PDF_TOK_OBJ;
531			break;
532		case 'e':
533			if (!strcmp(key, "endobj")) return PDF_TOK_ENDOBJ;
534			if (!strcmp(key, "endstream")) return PDF_TOK_ENDSTREAM;
535			break;
536		case 's':
537			if (!strcmp(key, "stream")) return PDF_TOK_STREAM;
538			if (!strcmp(key, "startxref")) return PDF_TOK_STARTXREF;
539			break;
540		case 'x':
541			if (!strcmp(key, "xref")) return PDF_TOK_XREF;
542			break;
543		}
544	
545		while (*key)
546		{
547			if (!fz_isprint(*key))
548				return PDF_TOK_ERROR;
549			++key;
550		}
551	
552		return PDF_TOK_KEYWORD;
553	}
554	
555	void pdf_lexbuf_init(fz_context *ctx, pdf_lexbuf *lb, int size)
556	{
557		lb->size = lb->base_size = size;
558		lb->len = 0;
559		lb->scratch = &lb->buffer[0];
560	}
561	
562	void pdf_lexbuf_fin(fz_context *ctx, pdf_lexbuf *lb)
563	{
564		if (lb && lb->size != lb->base_size)
565			fz_free(ctx, lb->scratch);
566	}
567	
568	ptrdiff_t pdf_lexbuf_grow(fz_context *ctx, pdf_lexbuf *lb)
569	{
570		char *old = lb->scratch;
571		size_t newsize = lb->size * 2;
572		if (lb->size == lb->base_size)
573		{
574			lb->scratch = Memento_label(fz_malloc(ctx, newsize), "pdf_lexbuf");
575			memcpy(lb->scratch, lb->buffer, lb->size);
576		}
577		else
578		{
579			lb->scratch = fz_realloc(ctx, lb->scratch, newsize);
580		}
581		lb->size = newsize;
582		return lb->scratch - old;
583	}
584	
585	pdf_token
586	pdf_lex(fz_context *ctx, fz_stream *f, pdf_lexbuf *buf)
587	{
588		while (1)
589		{
590			int c = lex_byte(ctx, f);
591			switch (c)
592			{
593			case EOF:
594				return PDF_TOK_EOF;
595			case IS_WHITE:
596				lex_white(ctx, f);
597				break;
598			case '%':
599				lex_comment(ctx, f);
600				break;
601			case '/':
602				lex_name(ctx, f, buf);
603				return PDF_TOK_NAME;
604			case '(':
605				return lex_string(ctx, f, buf);
606			case ')':
607				return PDF_TOK_ERROR;
608			case '<':
609				c = lex_byte(ctx, f);
610				if (c == '<')
611					return PDF_TOK_OPEN_DICT;
612				if (c != EOF)
613					fz_unread_byte(ctx, f);
614				return lex_hex_string(ctx, f, buf);
615			case '>':
616				c = lex_byte(ctx, f);
617				if (c == '>')
618					return PDF_TOK_CLOSE_DICT;
619				if (c != EOF)
620					fz_unread_byte(ctx, f);
621				return PDF_TOK_ERROR;
622			case '[':
623				return PDF_TOK_OPEN_ARRAY;
624			case ']':
625				return PDF_TOK_CLOSE_ARRAY;
626			case '{':
627				return PDF_TOK_OPEN_BRACE;
628			case '}':
629				return PDF_TOK_CLOSE_BRACE;
630			case IS_NUMBER:
631				return lex_number(ctx, f, buf, c);
632			default: /* isregular: !isdelim && !iswhite && c != EOF */
633				fz_unread_byte(ctx, f);
634				lex_name(ctx, f, buf);
635				return pdf_token_from_keyword(buf->scratch);
636			}
637		}
638	}
639	
640	pdf_token
641	pdf_lex_no_string(fz_context *ctx, fz_stream *f, pdf_lexbuf *buf)
642	{
643		while (1)
644		{
645			int c = lex_byte(ctx, f);
646			switch (c)
647			{
648			case EOF:
649				return PDF_TOK_EOF;
650			case IS_WHITE:
651				lex_white(ctx, f);
652				break;
653			case '%':
654				lex_comment(ctx, f);
655				break;
656			case '/':
657				lex_name(ctx, f, buf);
658				return PDF_TOK_NAME;
659			case '(':
660				return PDF_TOK_ERROR; /* no strings allowed */
661			case ')':
662				return PDF_TOK_ERROR; /* no strings allowed */
663			case '<':
664				c = lex_byte(ctx, f);
665				if (c == '<')
666					return PDF_TOK_OPEN_DICT;
667				if (c != EOF)
668					fz_unread_byte(ctx, f);
669				return PDF_TOK_ERROR; /* no strings allowed */
670			case '>':
671				c = lex_byte(ctx, f);
672				if (c == '>')
673					return PDF_TOK_CLOSE_DICT;
674				if (c != EOF)
675					fz_unread_byte(ctx, f);
676				return PDF_TOK_ERROR;
677			case '[':
678				return PDF_TOK_OPEN_ARRAY;
679			case ']':
680				return PDF_TOK_CLOSE_ARRAY;
681			case '{':
682				return PDF_TOK_OPEN_BRACE;
683			case '}':
684				return PDF_TOK_CLOSE_BRACE;
685			case IS_NUMBER:
686				return lex_number(ctx, f, buf, c);
687			default: /* isregular: !isdelim && !iswhite && c != EOF */
688				fz_unread_byte(ctx, f);
689				lex_name(ctx, f, buf);
690				return pdf_token_from_keyword(buf->scratch);
691			}
692		}
693	}
694	
695	void pdf_append_token(fz_context *ctx, fz_buffer *fzbuf, int tok, pdf_lexbuf *buf)
696	{
697		switch (tok)
698		{
699		case PDF_TOK_NAME:
700			fz_append_printf(ctx, fzbuf, "/%s", buf->scratch);
701			break;
702		case PDF_TOK_STRING:
703			if (buf->len >= buf->size)
704				pdf_lexbuf_grow(ctx, buf);
705			buf->scratch[buf->len] = 0;
706			fz_append_pdf_string(ctx, fzbuf, buf->scratch);
707			break;
708		case PDF_TOK_OPEN_DICT:
709			fz_append_string(ctx, fzbuf, "<<");
710			break;
711		case PDF_TOK_CLOSE_DICT:
712			fz_append_string(ctx, fzbuf, ">>");
713			break;
714		case PDF_TOK_OPEN_ARRAY:
715			fz_append_byte(ctx, fzbuf, '[');
716			break;
717		case PDF_TOK_CLOSE_ARRAY:
718			fz_append_byte(ctx, fzbuf, ']');
719			break;
720		case PDF_TOK_OPEN_BRACE:
721			fz_append_byte(ctx, fzbuf, '{');
722			break;
723		case PDF_TOK_CLOSE_BRACE:
724			fz_append_byte(ctx, fzbuf, '}');
725			break;
726		case PDF_TOK_INT:
727			fz_append_printf(ctx, fzbuf, "%ld", buf->i);
728			break;
729		case PDF_TOK_REAL:
730			fz_append_printf(ctx, fzbuf, "%g", buf->f);
731			break;
732		default:
733			fz_append_data(ctx, fzbuf, buf->scratch, buf->len);
734			break;
735		}
736	}
