278	static size_t
279	skip_language_code_utf16le(const unsigned char *s, size_t n, size_t i)
280	{
281		/* skip language escape codes */
282		if (i + 6 <= n && s[i+1] == 0 && s[i+0] == 27 && s[i+5] == 0 && s[i+4] == 27)
283			return 6;
284		else if (i + 8 <= n && s[i+1] == 0 && s[i+0] == 27 && s[i+7] == 0 && s[i+6] == 27)
285			return 8;
286		return 0;
287	}
288	
289	static size_t
290	skip_language_code_utf16be(const unsigned char *s, size_t n, size_t i)
291	{
292		/* skip language escape codes */
293		if (i + 6 <= n && s[i+0] == 0 && s[i+1] == 27 && s[i+4] == 0 && s[i+5] == 27)
294			return 6;
295		else if (i + 8 <= n && s[i+0] == 0 && s[i+1] == 27 && s[i+6] == 0 && s[i+7] == 27)
296			return 8;
297		return 0;
298	}
299	
300	static size_t
301	skip_language_code_utf8(const unsigned char *s, size_t n, size_t i)
302	{
303		/* skip language escape codes */
304		if (i + 3 <= n && s[i] == 27 && s[i+3])
305			return 3;
306		else if (i + 5 <= n && s[i] == 27 && s[i+5] == 27)
307			return 5;
308		return 0;
309	}
310	
311	static int
312	is_valid_utf8(const unsigned char *s, const unsigned char *end)
313	{
314		for (; s < end; ++s)
315		{
316			int c = *s;
317			int skip = c < 0x80 ? 0 : c < 0xC0 ? -1 : c < 0xE0 ? 1 : c < 0xF0 ? 2 : c < 0xF5 ? 3 : -1;
318			if (c >= 0x18 && c <= 0x1f) // Reserved control characters used by PDFDocEncoding.
319				return 0;
320			if (skip == -1)
321				return 0;
322			while (skip-- > 0)
323				if (++s >= end || (*s & 0xC0) != 0x80)
324					return 0;
325		}
326		return 1;
327	}
328	
329	char *
330	pdf_new_utf8_from_pdf_string(fz_context *ctx, const char *ssrcptr, size_t srclen)
331	{
332		const unsigned char *srcptr = (const unsigned char*)ssrcptr;
333		char *dstptr, *dst;
334		size_t dstlen = 0;
335		int ucs;
336		size_t i, n;
337	
338		/* UTF-16BE */
339		if (srclen >= 2 && srcptr[0] == 254 && srcptr[1] == 255)
340		{
341			i = 2;
342			while (i + 2 <= srclen)
343			{
344				n = skip_language_code_utf16be(srcptr, srclen, i);
345				if (n)
346					i += n;
347				else
348				{
349					i += rune_from_utf16be(&ucs, srcptr + i, srcptr + srclen);
350					dstlen += fz_runelen(ucs);
351				}
352			}
353	
354			dstptr = dst = Memento_label(fz_malloc(ctx, dstlen + 1), "utf8_from_utf16be");
355	
356			i = 2;
357			while (i + 2 <= srclen)
358			{
359				n = skip_language_code_utf16be(srcptr, srclen, i);
360				if (n)
361					i += n;
362				else
363				{
364					i += rune_from_utf16be(&ucs, srcptr + i, srcptr + srclen);
365					dstptr += fz_runetochar(dstptr, ucs);
366				}
367			}
368		}
369	
370		/* UTF-16LE */
371		else if (srclen >= 2 && srcptr[0] == 255 && srcptr[1] == 254)
372		{
373			i = 2;
374			while (i + 2 <= srclen)
375			{
376				n = skip_language_code_utf16le(srcptr, srclen, i);
377				if (n)
378					i += n;
379				else
380				{
381					i += rune_from_utf16le(&ucs, srcptr + i, srcptr + srclen);
382					dstlen += fz_runelen(ucs);
383				}
384			}
385	
386			dstptr = dst = Memento_label(fz_malloc(ctx, dstlen + 1), "utf8_from_utf16le");
387	
388			i = 2;
389			while (i + 2 <= srclen)
390			{
391				n = skip_language_code_utf16le(srcptr, srclen, i);
392				if (n)
393					i += n;
394				else
395				{
396					i += rune_from_utf16le(&ucs, srcptr + i, srcptr + srclen);
397					dstptr += fz_runetochar(dstptr, ucs);
398				}
399			}
400		}
401	
402		/* UTF-8 */
403		else if (srclen >= 3 && srcptr[0] == 239 && srcptr[1] == 187 && srcptr[2] == 191)
404		{
405			i = 3;
406			while (i < srclen)
407			{
408				n = skip_language_code_utf8(srcptr, srclen, i);
409				if (n)
410					i += n;
411				else
412				{
413					i += 1;
414					dstlen += 1;
415				}
416			}
417	
418			dstptr = dst = Memento_label(fz_malloc(ctx, dstlen + 1), "utf8_from_utf8");
419	
420			i = 3;
421			while (i < srclen)
422			{
423				n = skip_language_code_utf8(srcptr, srclen, i);
424				if (n)
425					i += n;
426				else
427					*dstptr++ = srcptr[i++];
428			}
429		}
430	
431		/* Detect UTF-8 strings that aren't marked with a BOM */
432		else if (is_valid_utf8(srcptr, srcptr + srclen))
433		{
434			dst = Memento_label(fz_malloc(ctx, srclen + 1), "utf8_from_guess");
435			memcpy(dst, srcptr, srclen);
436			dstptr = dst + srclen;
437		}
438	
439		/* PDFDocEncoding */
440		else
441		{
442			for (i = 0; i < srclen; i++)
443				dstlen += fz_runelen(fz_unicode_from_pdf_doc_encoding[srcptr[i]]);
444	
445			dstptr = dst = Memento_label(fz_malloc(ctx, dstlen + 1), "utf8_from_pdfdocenc");
446	
447			for (i = 0; i < srclen; i++)
448			{
449				ucs = fz_unicode_from_pdf_doc_encoding[srcptr[i]];
450				dstptr += fz_runetochar(dstptr, ucs);
451			}
452		}
453	
454		*dstptr = 0;
455		return dst;
456	}
