468	pdf_new_utf8_from_pdf_stream_obj(fz_context *ctx, pdf_obj *src)
469	{
470		fz_buffer *stmbuf;
471		char *srcptr;
472		size_t srclen;
473		char *dst = NULL;
474	
475		stmbuf = pdf_load_stream(ctx, src);
476		srclen = fz_buffer_storage(ctx, stmbuf, (unsigned char **)&srcptr);
477		fz_try(ctx)
478			dst = pdf_new_utf8_from_pdf_string(ctx, srcptr, srclen);
479		fz_always(ctx)
