494	static pdf_obj *
495	pdf_new_text_string_utf16be(fz_context *ctx, const char *s)
496	{
497		const char *ss;
498		int c, i, n, a, b;
499		unsigned char *p;
500		pdf_obj *obj;
501	
502		ss = s;
503		n = 0;
504		while (*ss)
505		{
506			ss += fz_chartorune(&c, ss);
507			n += (c >= 0x10000) ? 2 : 1;
508		}
509	
510		p = fz_malloc(ctx, n * 2 + 2);
511		i = 0;
512		p[i++] = 254;
513		p[i++] = 255;
514		while (*s)
515		{
516			s += fz_chartorune(&c, s);
517			if (c >= 0x10000)
518			{
519				a = (((c - 0x10000) >> 10) & 0x3ff) + 0xD800;
520				p[i++] = (a>>8) & 0xff;
521				p[i++] = (a) & 0xff;
522				b = (((c - 0x10000)) & 0x3ff) + 0xDC00;
523				p[i++] = (b>>8) & 0xff;
524				p[i++] = (b) & 0xff;
525			}
526			else
527			{
528				p[i++] = (c>>8) & 0xff;
529				p[i++] = (c) & 0xff;
530			}
531		}
532	
533		fz_try(ctx)
534			obj = pdf_new_string(ctx, (char*)p, i);
535		fz_always(ctx)
536			fz_free(ctx, p);
537		fz_catch(ctx)
538			fz_rethrow(ctx);
539		return obj;
540	}
541	
542	pdf_obj *
543	pdf_new_text_string(fz_context *ctx, const char *s)
544	{
545		int i = 0;
546		while (s[i] != 0)
547		{
548			if (((unsigned char)s[i]) >= 128)
549				return pdf_new_text_string_utf16be(ctx, s);
550			++i;
551		}
552		return pdf_new_string(ctx, s, i);
553	}
554	
555	pdf_obj *
556	pdf_parse_array(fz_context *ctx, pdf_document *doc, fz_stream *file, pdf_lexbuf *buf)
557	{
558		pdf_obj *ary = NULL;
559		pdf_obj *obj = NULL;
560		int64_t a = 0, b = 0, n = 0;
561		pdf_token tok;
562		pdf_obj *op = NULL;
563	
564		fz_var(obj);
565	
566		ary = pdf_new_array(ctx, doc, 4);
567	
568		fz_try(ctx)
569		{
570			while (1)
571			{
572				tok = pdf_lex(ctx, file, buf);
573	
574				if (tok != PDF_TOK_INT && tok != PDF_TOK_R)
575				{
576					if (n > 0)
577						pdf_array_push_int(ctx, ary, a);
578					if (n > 1)
579						pdf_array_push_int(ctx, ary, b);
580					n = 0;
581				}
582	
583				if (tok == PDF_TOK_INT && n == 2)
584				{
585					pdf_array_push_int(ctx, ary, a);
586					a = b;
587					n --;
588				}
589	
590				switch (tok)
591				{
592				case PDF_TOK_EOF:
593					fz_throw(ctx, FZ_ERROR_SYNTAX, "array not closed before end of file");
594	
595				case PDF_TOK_CLOSE_ARRAY:
596					op = ary;
597					goto end;
598	
599				case PDF_TOK_INT:
600					if (n == 0)
601						a = buf->i;
602					if (n == 1)
603						b = buf->i;
604					n ++;
605					break;
606	
607				case PDF_TOK_R:
608					if (n != 2)
609						fz_throw(ctx, FZ_ERROR_SYNTAX, "cannot parse indirect reference in array");
610					pdf_array_push_drop(ctx, ary, pdf_new_indirect(ctx, doc, a, b));
611					n = 0;
612					break;
613	
614				case PDF_TOK_OPEN_ARRAY:
615					obj = pdf_parse_array(ctx, doc, file, buf);
616					pdf_array_push_drop(ctx, ary, obj);
617					break;
618	
619				case PDF_TOK_OPEN_DICT:
620					obj = pdf_parse_dict(ctx, doc, file, buf);
621					pdf_array_push_drop(ctx, ary, obj);
622					break;
623	
624				case PDF_TOK_NAME:
625					pdf_array_push_name(ctx, ary, buf->scratch);
626					break;
627				case PDF_TOK_REAL:
628					pdf_array_push_real(ctx, ary, buf->f);
629					break;
630				case PDF_TOK_STRING:
631					pdf_array_push_string(ctx, ary, buf->scratch, buf->len);
632					break;
633				case PDF_TOK_TRUE:
634					pdf_array_push_bool(ctx, ary, 1);
635					break;
636				case PDF_TOK_FALSE:
637					pdf_array_push_bool(ctx, ary, 0);
638					break;
639				case PDF_TOK_NULL:
640					pdf_array_push(ctx, ary, PDF_NULL);
641					break;
642	
643				default:
644					pdf_array_push(ctx, ary, PDF_NULL);
645					break;
646				}
647			}
648	end:
649			{}
650		}
651		fz_catch(ctx)
652		{
653			pdf_drop_obj(ctx, ary);
654			fz_rethrow(ctx);
655		}
656		return op;
657	}
658	
659	pdf_obj *
660	pdf_parse_dict(fz_context *ctx, pdf_document *doc, fz_stream *file, pdf_lexbuf *buf)
661	{
662		pdf_obj *dict;
663		pdf_obj *key = NULL;
664		pdf_obj *val = NULL;
665		pdf_token tok;
666		int64_t a, b;
667	
668		dict = pdf_new_dict(ctx, doc, 8);
669	
670		fz_var(key);
671		fz_var(val);
672	
673		fz_try(ctx)
674		{
675			while (1)
676			{
677				tok = pdf_lex(ctx, file, buf);
678		skip:
679				if (tok == PDF_TOK_CLOSE_DICT)
680					break;
681	
682				/* for BI .. ID .. EI in content streams */
683				if (tok == PDF_TOK_KEYWORD && !strcmp(buf->scratch, "ID"))
684					break;
685	
686				if (tok != PDF_TOK_NAME)
687					fz_throw(ctx, FZ_ERROR_SYNTAX, "invalid key in dict");
688	
689				key = pdf_new_name(ctx, buf->scratch);
690	
691				tok = pdf_lex(ctx, file, buf);
692	
693				switch (tok)
694				{
695				case PDF_TOK_OPEN_ARRAY:
696					val = pdf_parse_array(ctx, doc, file, buf);
697					break;
698	
699				case PDF_TOK_OPEN_DICT:
700					val = pdf_parse_dict(ctx, doc, file, buf);
701					break;
702	
703				case PDF_TOK_NAME: val = pdf_new_name(ctx, buf->scratch); break;
704				case PDF_TOK_REAL: val = pdf_new_real(ctx, buf->f); break;
705				case PDF_TOK_STRING: val = pdf_new_string(ctx, buf->scratch, buf->len); break;
706				case PDF_TOK_TRUE: val = PDF_TRUE; break;
707				case PDF_TOK_FALSE: val = PDF_FALSE; break;
708				case PDF_TOK_NULL: val = PDF_NULL; break;
709	
710				case PDF_TOK_INT:
711					/* 64-bit to allow for numbers > INT_MAX and overflow */
712					a = buf->i;
713					tok = pdf_lex(ctx, file, buf);
714					if (tok == PDF_TOK_CLOSE_DICT || tok == PDF_TOK_NAME ||
715						(tok == PDF_TOK_KEYWORD && !strcmp(buf->scratch, "ID")))
716					{
717						pdf_dict_put_int(ctx, dict, key, a);
718						pdf_drop_obj(ctx, key);
719						key = NULL;
720						goto skip;
721					}
722					if (tok == PDF_TOK_INT)
723					{
724						b = buf->i;
725						tok = pdf_lex(ctx, file, buf);
726						if (tok == PDF_TOK_R)
727						{
728							val = pdf_new_indirect(ctx, doc, a, b);
729							break;
730						}
731					}
732					fz_warn(ctx, "invalid indirect reference in dict");
733					val = PDF_NULL;
734					break;
735	
736				default:
737					val = PDF_NULL;
738					break;
739				}
740	
741				pdf_dict_put(ctx, dict, key, val);
742				pdf_drop_obj(ctx, val);
743				val = NULL;
744				pdf_drop_obj(ctx, key);
745				key = NULL;
746			}
747		}
748		fz_catch(ctx)
749		{
750			pdf_drop_obj(ctx, dict);
751			pdf_drop_obj(ctx, key);
752			pdf_drop_obj(ctx, val);
753			fz_rethrow(ctx);
754		}
755		return dict;
756	}
757	
758	pdf_obj *
759	pdf_parse_stm_obj(fz_context *ctx, pdf_document *doc, fz_stream *file, pdf_lexbuf *buf)
760	{
761		pdf_token tok;
762	
763		tok = pdf_lex(ctx, file, buf);
764	
765		switch (tok)
766		{
767		case PDF_TOK_OPEN_ARRAY:
768			return pdf_parse_array(ctx, doc, file, buf);
769		case PDF_TOK_OPEN_DICT:
770			return pdf_parse_dict(ctx, doc, file, buf);
771		case PDF_TOK_NAME: return pdf_new_name(ctx, buf->scratch);
772		case PDF_TOK_REAL: return pdf_new_real(ctx, buf->f);
773		case PDF_TOK_STRING: return pdf_new_string(ctx, buf->scratch, buf->len);
774		case PDF_TOK_TRUE: return PDF_TRUE;
775		case PDF_TOK_FALSE: return PDF_FALSE;
776		case PDF_TOK_NULL: return PDF_NULL;
777		case PDF_TOK_INT: return pdf_new_int(ctx, buf->i);
778		default: fz_throw(ctx, FZ_ERROR_SYNTAX, "unknown token in object stream");
779		}
780	}
781	
782	pdf_obj *
783	pdf_parse_ind_obj_or_newobj(fz_context *ctx, pdf_document *doc, fz_stream *file,
784		int *onum, int *ogen, int64_t *ostmofs, int *try_repair, int *newobj)
785	{
786		pdf_obj *obj = NULL;
787		int num = 0, gen = 0;
788		int64_t stm_ofs;
789		pdf_token tok;
790		pdf_lexbuf *buf = &doc->lexbuf.base;
791		int64_t a, b;
792		int read_next_token = 1;
793	
794		fz_var(obj);
795	
796		tok = pdf_lex(ctx, file, buf);
797		if (tok != PDF_TOK_INT)
798		{
799			if (try_repair)
800				*try_repair = 1;
801			fz_throw(ctx, FZ_ERROR_SYNTAX, "expected object number");
802		}
803		num = buf->i;
804		if (num < 0 || num > PDF_MAX_OBJECT_NUMBER)
805			fz_throw(ctx, FZ_ERROR_SYNTAX, "object number out of range");
806	
807		tok = pdf_lex(ctx, file, buf);
808		if (tok != PDF_TOK_INT)
809		{
810			if (try_repair)
811				*try_repair = 1;
812			fz_throw(ctx, FZ_ERROR_SYNTAX, "expected generation number (%d ? obj)", num);
813		}
814		gen = buf->i;
815		if (gen < 0 || gen >= 65536)
816		{
817			if (try_repair)
818				*try_repair = 1;
819			fz_throw(ctx, FZ_ERROR_SYNTAX, "invalid generation number (%d)", gen);
820		}
821	
822		tok = pdf_lex(ctx, file, buf);
823		if (tok == PDF_TOK_NEWOBJ && newobj)
824		{
825			*newobj = 1;
826			if (onum) *onum = num;
827			if (ogen) *ogen = gen;
828			if (ostmofs) *ostmofs = 0;
829			return NULL;
830		}
831		if (tok != PDF_TOK_OBJ)
832		{
833			if (try_repair)
834				*try_repair = 1;
835			fz_throw(ctx, FZ_ERROR_SYNTAX, "expected 'obj' keyword (%d %d ?)", num, gen);
836		}
837	
838		tok = pdf_lex(ctx, file, buf);
839	
840		switch (tok)
841		{
842		case PDF_TOK_OPEN_ARRAY:
843			obj = pdf_parse_array(ctx, doc, file, buf);
844			break;
845	
846		case PDF_TOK_OPEN_DICT:
847			obj = pdf_parse_dict(ctx, doc, file, buf);
848			break;
849	
850		case PDF_TOK_NAME: obj = pdf_new_name(ctx, buf->scratch); break;
851		case PDF_TOK_REAL: obj = pdf_new_real(ctx, buf->f); break;
852		case PDF_TOK_STRING: obj = pdf_new_string(ctx, buf->scratch, buf->len); break;
853		case PDF_TOK_TRUE: obj = PDF_TRUE; break;
854		case PDF_TOK_FALSE: obj = PDF_FALSE; break;
855		case PDF_TOK_NULL: obj = PDF_NULL; break;
856	
857		case PDF_TOK_INT:
858			a = buf->i;
859			tok = pdf_lex(ctx, file, buf);
860	
861			if (tok == PDF_TOK_STREAM || tok == PDF_TOK_ENDOBJ)
862			{
863				obj = pdf_new_int(ctx, a);
864				read_next_token = 0;
865				break;
866			}
867			else if (tok == PDF_TOK_INT)
868			{
869				b = buf->i;
870				tok = pdf_lex(ctx, file, buf);
871				if (tok == PDF_TOK_R)
872				{
873					obj = pdf_new_indirect(ctx, doc, a, b);
874					break;
875				}
876			}
877			fz_throw(ctx, FZ_ERROR_SYNTAX, "expected 'R' keyword (%d %d R)", num, gen);
878	
879		case PDF_TOK_ENDOBJ:
880			obj = PDF_NULL;
881			read_next_token = 0;
882			break;
883	
884		default:
885			fz_throw(ctx, FZ_ERROR_SYNTAX, "syntax error in object (%d %d R)", num, gen);
886		}
887	
888		fz_try(ctx)
889		{
890			if (read_next_token)
891				tok = pdf_lex(ctx, file, buf);
892	
893			if (tok == PDF_TOK_STREAM)
894			{
895				int c = fz_read_byte(ctx, file);
896				while (c == ' ')
897					c = fz_read_byte(ctx, file);
898				if (c == '\r')
899				{
900					c = fz_peek_byte(ctx, file);
901					if (c != '\n')
902						fz_warn(ctx, "line feed missing after stream begin marker (%d %d R)", num, gen);
903					else
904						fz_read_byte(ctx, file);
905				}
906				stm_ofs = fz_tell(ctx, file);
907			}
908			else if (tok == PDF_TOK_ENDOBJ)
909			{
910				stm_ofs = 0;
911			}
912			else
913			{
914				fz_warn(ctx, "expected 'endobj' or 'stream' keyword (%d %d R)", num, gen);
915				stm_ofs = 0;
916			}
917		}
918		fz_catch(ctx)
919		{
920			pdf_drop_obj(ctx, obj);
921			fz_rethrow(ctx);
922		}
923	
924		if (onum) *onum = num;
925		if (ogen) *ogen = gen;
926		if (ostmofs) *ostmofs = stm_ofs;
927	
928		return obj;
929	}
930	
931	pdf_obj *
932	pdf_parse_ind_obj(fz_context *ctx, pdf_document *doc, fz_stream *file,
933		int *onum, int *ogen, int64_t *ostmofs, int *try_repair)
934	{
935		return pdf_parse_ind_obj_or_newobj(ctx, doc, file, onum, ogen, ostmofs, try_repair, NULL);
936	}
937	
938	pdf_obj *
939	pdf_parse_journal_obj(fz_context *ctx, pdf_document *doc, fz_stream *stm,
940		int *onum, fz_buffer **ostm, int *newobj)
941	{
942		pdf_obj *obj = NULL;
943		pdf_token tok;
944		pdf_lexbuf *buf = &doc->lexbuf.base;
945		int64_t stmofs;
946	
947		*newobj = 0;
948		obj = pdf_parse_ind_obj_or_newobj(ctx, doc, stm, onum, NULL, &stmofs, NULL, newobj);
949		/* This will have consumed either the stream or the endobj keywords. */
950	
951		*ostm = NULL;
952		if (stmofs)
953		{
954			fz_stream *stream = NULL;
955	
956			fz_var(stream);
957	
958			fz_try(ctx)
959			{
960				stream = fz_open_endstream_filter(ctx, stm, 0, stmofs);
961				*ostm = fz_read_all(ctx, stream, 32);
962				fz_drop_stream(ctx, stream);
963				stream = NULL;
964				fz_seek(ctx, stm, stmofs + (*ostm ? (*ostm)->len : 0), SEEK_SET);
965				tok = pdf_lex(ctx, stm, buf);
966				if (tok != PDF_TOK_ENDSTREAM)
967					fz_throw(ctx, FZ_ERROR_SYNTAX, "expected 'endstream' keyword");
968				tok = pdf_lex(ctx, stm, buf);
969				if (tok != PDF_TOK_ENDOBJ)
970					fz_throw(ctx, FZ_ERROR_SYNTAX, "expected 'endobj' keyword");
971			}
972			fz_always(ctx)
973				fz_drop_stream(ctx, stream);
974			fz_catch(ctx)
975			{
976				pdf_drop_obj(ctx, obj);
977				fz_rethrow(ctx);
978			}
979		}
980	
981		return obj;
982	}
